&lt;th style=&#34;text-align:left&#34;&gt;Bucket Policy/Notification Operations&lt;/th&gt;
&lt;th style=&#34;text-align:left&#34;&gt;Client custom settings&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;&lt;a href=&#34;https://min.io/docs/minio/linux/developers/go/API.html#MakeBucket&#34;&gt; &lt;code&gt;MakeBucket&lt;/code&gt; &lt;/a&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;&lt;a href=&#34;https://min.io/docs/minio/linux/developers/go/API.html#GetObject&#34;&gt; &lt;code&gt;GetObject&lt;/code&gt; &lt;/a&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;&lt;a href=&#34;https://min.io/docs/minio/linux/developers/go/API.html#PresignedGetObject&#34;&gt; &lt;code&gt;PresignedGetObject&lt;/code&gt; &lt;/a&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;&lt;a href=&#34;https://min.io/docs/minio/linux/developers/go/API.html#SetBucketPolicy&#34;&gt; &lt;code&gt;SetBucketPolicy&lt;/code&gt; &lt;/a&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;&lt;a href=&#34;https://min.io/docs/minio/linux/developers/go/API.html#SetAppInfo&#34;&gt; &lt;code&gt;SetAppInfo&lt;/code&gt; &lt;/a&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;&lt;/td&gt;
